---
import '../styles/global.css';
import cjkFontsHref from '../styles/cjk-fonts.css?url';

interface Props {
  title: string;
  description?: string;
  lang?: string;
}

const {
  title,
  description = 'A Chinese-heritage, university-adjacent Christian community in Ithaca, NY.',
  lang = 'en',
} = Astro.props;
---

<!doctype html>
<html lang={lang}>
  <head>
    <meta charset="utf-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1" />
    <title>{title}</title>
    {description && <meta name="description" content={description} />}
    <link rel="stylesheet" href={cjkFontsHref} media="print" onload="this.media='all'" />
    <noscript><link rel="stylesheet" href={cjkFontsHref} /></noscript>
  </head>
  <body>
    <slot />
  </body>
</html>

/* ==========================================================================
   FICCC Design Tokens & Global Styles
   Palette: "Gathered Warmth" (D007)
   ========================================================================== */

/* --- Font imports (self-hosted via fontsource) --- */
@import '@fontsource-variable/lora';
@import '@fontsource-variable/inter';

/* ==========================================================================
   CSS Custom Properties
   ========================================================================== */

:root {
  /* --- Colors: Gathered Warmth palette --- */
  --color-bg:          #FAF8F5;  /* off-white background       */
  --color-stone:       #E8E0D8;  /* warm stone / borders        */
  --color-terracotta:  #C4745A;  /* muted terracotta / accent   */
  --color-ink:         #1A1A2E;  /* deep ink / headings         */
  --color-body:        #2D2D2D;  /* body text                   */

  /* --- Spacing: 4px base scale --- */
  --space-1:    4px;   /*  4 */
  --space-2:    8px;   /*  8 */
  --space-3:   12px;   /* 12 */
  --space-4:   16px;   /* 16 */
  --space-6:   24px;   /* 24 */
  --space-8:   32px;   /* 32 */
  --space-12:  48px;   /* 48 */
  --space-16:  64px;   /* 64 */

[105 more lines in file. Use offset=31 to continue.]

  --space-24:  96px;   /* 96 */
  --space-32: 128px;   /* 128 */

  /* --- Font families --- */
  --font-heading:  'Lora Variable', 'Noto Serif SC', Georgia, serif;
  --font-body:     'Inter Variable', 'Noto Serif SC', system-ui, sans-serif;
  --font-cjk:      'Noto Serif SC', 'Lora Variable', serif;

  /* --- Type scale (EN) — modular, ~1.25 ratio --- */
  --text-xs:     0.75rem;   /* 12px */
  --text-sm:     0.875rem;  /* 14px */
  --text-base:   1rem;      /* 16px */
  --text-lg:     1.25rem;   /* 20px */
  --text-xl:     1.5rem;    /* 24px */
  --text-2xl:    2rem;      /* 32px */
  --text-3xl:    2.5rem;    /* 40px */
  --text-4xl:    3rem;      /* 48px */

  /* --- Line heights --- */
  --leading-tight:   1.25;
  --leading-normal:  1.5;
  --leading-relaxed: 1.65;
  --leading-cjk:     1.75;

  /* --- Type scale (ZH) — slightly larger base for readability --- */
  --text-zh-base:  1.125rem;  /* 18px */
  --text-zh-lg:    1.375rem;  /* 22px */
  --text-zh-xl:    1.625rem;  /* 26px */
  --text-zh-2xl:   2.125rem;  /* 34px */
  --text-zh-3xl:   2.625rem;  /* 42px */

  /* --- Misc --- */
  --radius-sm:  4px;
  --radius-md:  8px;
  --radius-lg: 16px;
  --transition: 200ms ease;
}

/* ==========================================================================
   Minimal Reset
   ========================================================================== */

*,
*::before,
*::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html {
  -webkit-text-size-adjust: 100%;
  -moz-text-size-adjust: 100%;
  text-size-adjust: 100%;
  scroll-behavior: smooth;
}

body {
  font-family: var(--font-body);
  font-size: var(--text-base);
  line-height: var(--leading-normal);
  color: var(--color-body);
  background-color: var(--color-bg);
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

img,
picture,
video,
canvas,
svg {
  display: block;
  max-width: 100%;
}

input,
button,
textarea,
select {
  font: inherit;
}

h1, h2, h3, h4, h5, h6 {
  font-family: var(--font-heading);
  color: var(--color-ink);
  line-height: var(--leading-tight);
  text-wrap: balance;
}

p {
  text-wrap: pretty;
}

a {
  color: var(--color-terracotta);
  text-decoration-skip-ink: auto;
}

/* --- CJK utility --- */
:lang(zh) {
  font-family: var(--font-cjk);
  line-height: var(--leading-cjk);
}

/* CJK font loaded asynchronously to avoid blocking render */
@import '@fontsource/noto-serif-sc/400.css';
@import '@fontsource/noto-serif-sc/700.css';

arguments.content:
module.exports = {
  ci: {
    collect: {
      startServerCommand: 'npm run preview',
      startServerReadyPattern: 'Local',
      url: ['http://localhost:4321/', 'http://localhost:4321/styleguide/'],
      numberOfRuns: 3,
    },
    assert: {
      assertMatrix: [
        {
          matchingUrlPattern: '.*://[^/]+/$',
          assertions: {
            'categories:performance': ['error', { minScore: 0.75 }],
            'categories:accessibility': ['error', { minScore: 0.95 }],
            'categories:seo': ['error', { minScore: 0.95 }],
            'categories:best-practices': ['error', { minScore: 0.9 }],
          },
        },
        {
          matchingUrlPattern: '.*/styleguide/.*',
          assertions: {
            'categories:performance': ['warn', { minScore: 0.5 }],
            'categories:accessibility': ['error', { minScore: 0.95 }],
            'categories:seo': ['error', { minScore: 0.95 }],
            'categories:best-practices': ['error', { minScore: 0.9 }],
          },
        },
      ],
    },
    upload: {
      target: 'temporary-public-storage',
    },
  },
};
